const fed = $('Get Federation').first().json;
const body = ($('Webhook').first().json.body) || {};
let items = [];
if (body.url) {
  items = [{ url: String(body.url), region: '' }];
} else {
  const dirs = Array.isArray(fed.directory_urls) ? fed.directory_urls : [];
  items = dirs
    .filter(d => d && ['static','js'].includes(d.extraction_method) && /^https?:\/\//.test(d.url || ''))
    .map(d => ({ url: d.url, region: d.region || '' }));
}
if (!items.length) return [{ json: { __skip: true, note: 'no static/js directory page' } }];
return items.map(it => ({ json: it }));

const PB_URL = ($('Config').first().json.pbUrl || '').replace(/\/+$/, '');
const token = $('PB Auth').first().json.token; const pbH = { Authorization: token };
const fed = $('Get Federation').first().json; const fedId = fed.id;
const setFed = (body) => this.helpers.httpRequest({ method:'PATCH', url:PB_URL+'/api/collections/federations/records/'+fedId, headers:pbH, body, json:true });

const picks = $('pick url').all().map(i => i.json);
if (picks.length === 1 && picks[0].__skip) {
  await setFed({ status:'needs_review', notes:picks[0].note });
  return [{ json: { ok:false, note: picks[0].note } }];
}
const scrapes = $('Firecrawl Scrape').all().map(i => i.json);
const agents  = $('Extract clubs').all().map(i => i.json);

const fivb = String(fed.fivb_code||'').toUpperCase(); const country = fed.country||'';
const dirs = Array.isArray(fed.directory_urls) ? fed.directory_urls : [];
const uslug = (s) => String(s||'').toLowerCase().normalize('NFKC').replace(/[^\p{L}\p{N}]+/gu,'-').replace(/^-+|-+$/g,'').slice(0,60);
const nkey  = (s) => String(s||'').toLowerCase().normalize('NFKD').replace(/\*+/g,'').replace(/\([^)]*\)/g,' ').replace(/[^\p{L}\p{N}]+/gu,'');   // anchor<->name match
const normUrl = (u) => { u=(u||'').trim().replace(/^https?:\/\//i,''); if(!u) return ''; if(/[\s,]/.test(u)||!u.includes('.')) return ''; return 'https://'+u; };
const now = new Date().toISOString();
const findByKey = async (k) => { const r = await this.helpers.httpRequest({ method:'GET', url:PB_URL+'/api/collections/clubs/records', qs:{ filter:"(dedup_key='"+k+"')", perPage:1 }, headers:pbH, json:true }); return (r.items&&r.items[0])||null; };
const hostOf = (u) => String(u||'').replace(/^https?:\/\//i,'').replace(/^www\./i,'').split('/')[0].toLowerCase();

let created=0, updated=0, failed=0, totalClubs=0, scrapeFails=0; const errors=[]; const perDir=[];
for (let i=0;i<picks.length;i++){
  const pick = picks[i]||{}; const fc = scrapes[i]||{}; const ag = agents[i]||{};
  const srcUrl = pick.url || '';
  const md = (fc && fc.data && fc.data.markdown) || '';
  if (!md){ scrapeFails++; errors.push({ url:srcUrl, message:'scrape failed: '+((fc&&(fc.error||fc.code))||'no markdown') }); continue; }

  const baseOrigin = (function(){ const m=String(srcUrl).match(/^(https?:\/\/[^/]+)/i); return m?m[1]:''; })();
  const dirHost = hostOf(baseOrigin);
  const absol = (u) => { u=String(u||'').trim(); if(!u) return ''; if(/^https?:\/\//i.test(u)) return u; if(u.startsWith('//')) return 'https:'+u; if(u.startsWith('/')) return baseOrigin ? baseOrigin+u : ''; return baseOrigin ? baseOrigin+'/'+u.replace(/^\.?\//,'') : ''; };

  // Deterministic backstop: normalized anchor text -> same-site href (skips in-page #anchors).
  const linkMap = {}; const re=/\[([^\]]*)\]\(([^)\s]+)\)/g; let mm;
  while((mm=re.exec(md))){ const a=nkey(mm[1]); let href=mm[2]; if(!a||!href||href.indexOf('#')>=0) continue; const abs=absol(href); if(!abs||hostOf(abs)!==dirHost) continue; if(!linkMap[a]) linkMap[a]=abs; }

  const entry = dirs.find(d => d && d.url === srcUrl) || {};
  const dirRegion = entry.region || pick.region || '';

  let raw=String(ag.output||'').trim().replace(/^```(json)?/i,'').replace(/```$/,'').trim();
  let parsed; try{ parsed=JSON.parse(raw); }catch(e){ const x=raw.match(/\{[\s\S]*\}/); parsed=x?JSON.parse(x[0]):{}; }
  const clubs = Array.isArray(parsed.clubs)?parsed.clubs:[];
  totalClubs += clubs.length; let dc=0, du=0;
  for (const c of clubs){
    const name = String(c.name||'').replace(/\*+/g,'').trim(); if(!name) continue;
    const city = String(c.city||'').trim(); const region = String(c.region||'').trim() || dirRegion;
    let website = normUrl(c.website);
    if (website && dirHost && hostOf(website)===dirHost) website='';   // not the club's own site
    let detail = absol(String(c.detail_url||'').trim());
    if (detail && hostOf(detail)!==dirHost) detail='';                 // must be same-site
    if (!detail){ const hit = linkMap[nkey(name)]; if(hit) detail=hit; } // backstop by club name
    const dedup = fivb+':'+uslug(name)+':'+uslug(city);
    const base = { federation:fedId, name, country, region, city, dedup_key:dedup, last_scraped:now };
    const full = Object.assign({}, base, { website_url:website, website_source: website?'official_list':'none', detail_url:detail, source_url:srcUrl, status:'new' });
    try {
      try { await this.helpers.httpRequest({ method:'POST', url:PB_URL+'/api/collections/clubs/records', headers:pbH, body:full, json:true }); created++; dc++; }
      catch(e){
        const ex = await findByKey(dedup);
        if (ex){
          const patch = Object.assign({}, base);                       // backfill: never blank a richer value
          if (website){ patch.website_url=website; patch.website_source='official_list'; }
          if (detail) patch.detail_url=detail;
          if (!ex.source_url) patch.source_url=srcUrl;
          await this.helpers.httpRequest({ method:'PATCH', url:PB_URL+'/api/collections/clubs/records/'+ex.id, headers:pbH, body:patch, json:true }); updated++; du++;
        } else throw e;
      }
    } catch(e){ failed++; if(errors.length<10) errors.push({ key:dedup, message:(e&&e.message)||String(e) }); }
  }
  perDir.push({ url:srcUrl, clubs:clubs.length, created:dc, updated:du });
}

let status;
if (created+updated>0 && failed===0) status='scraped';
else if (failed>0) status='error';
else if (scrapeFails>0 && created+updated===0) status='error';
else status='needs_review';     // scrapes ok but zero clubs
await setFed({ status, last_scraped:now });
return [{ json: { ok: failed===0 && status==='scraped', federation:fivb, directories:perDir, total:totalClubs, created, updated, failed, scrapeFails, errors } }];
